import path from 'node:path';
import { fileURLToPath } from 'node:url';

import { storybookTest } from '@storybook/addon-vitest/vitest-plugin';
import { playwright } from '@vitest/browser-playwright';
import { defineConfig } from 'vitest/config';

const dirname =
    typeof __dirname !== 'undefined' ? __dirname : path.dirname(fileURLToPath(import.meta.url));

// More info at: https://storybook.js.org/docs/next/writing-tests/integrations/vitest-addon
export default defineConfig({
    test: {
        projects: [
            {
                extends: true,
                plugins: [
                    // The plugin will run tests for the stories defined in your Storybook config
                    // See options at: https://storybook.js.org/docs/next/writing-tests/integrations/vitest-addon#storybooktest
                    storybookTest({ configDir: path.join(dirname, '.storybook') }),
                ],
                test: {
                    name: 'storybook',
                    // Must exceed the longest inner `waitFor` timeout used by
                    // any story (currently 10000ms, in PlayerCard/TeamPlayer/
                    // Team/GameDaySummary — they wait for a real
                    // ImageWithPlaceholder load event, which can take several
                    // seconds when the whole suite runs and many images
                    // decode under CPU contention at once) — otherwise this
                    // default (5000ms) kills the test before that waitFor
                    // gets to time out itself.
                    testTimeout: 15000,
                    browser: {
                        enabled: true,
                        headless: true,
                        provider: playwright({}),
                        instances: [{ browser: 'chromium' }],
                    },
                },
            },
        ],
    },
});

